import { NativeModules, Platform } from 'react-native';
import * as Keychain from 'react-native-keychain';

const { RNRandomBytes } = NativeModules;

class OfflineTokenGenerator {
  constructor() {
    this.tokenPrefix = 'offline_';
    this.keychainService = 'com.app.offline.tokens';
  }

  async generateSecureRandomBytes(length) {
    try {
      if (Platform.OS === 'web') {
        const array = new Uint8Array(length);
        crypto.getRandomValues(array);
        return Array.from(array);
      }

      const randomBytes = await new Promise((resolve, reject) => {
        if (RNRandomBytes && RNRandomBytes.randomBytes) {
          RNRandomBytes.randomBytes(length, (error, bytes) => {
            if (error) {
              reject(error);
            } else {
              resolve(bytes);
            }
          });
        } else {
          reject(new Error('RNRandomBytes not available'));
        }
      });

      return Array.from(randomBytes);
    } catch (error) {
      throw new Error('Failed to generate secure random bytes: ' + error.message);
    }
  }

  async generateToken() {
    try {
      const tokenLength = 32;
      const randomBytes = await this.generateSecureRandomBytes(tokenLength);
      
      const tokenString = randomBytes
        .map(byte => byte.toString(16).padStart(2, '0'))
        .join('');
      
      const timestamp = Date.now();
      const token = `${this.tokenPrefix}${timestamp}_${tokenString}`;
      
      await this.storeToken(token);
      
      return token;
    } catch (error) {
      throw new Error('Token generation failed: ' + error.message);
    }
  }

  async storeToken(token) {
    try {
      const existingTokens = await this.getStoredTokens();
      existingTokens.push({
        token,
        createdAt: Date.now(),
        synced: false
      });

      await Keychain.setGenericPassword(
        'offline_tokens',
        JSON.stringify(existingTokens),
        {
          service: this.keychainService,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED
        }
      );
    } catch (error) {
      throw new Error('Failed to store token securely: ' + error.message);
    }
  }

  async getStoredTokens() {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: this.keychainService
      });

      if (credentials && credentials.password) {
        return JSON.parse(credentials.password);
      }
      return [];
    } catch (error) {
      return [];
    }
  }

  async getCurrentToken() {
    try {
      const tokens = await this.getStoredTokens();
      if (tokens.length > 0) {
        return tokens[tokens.length - 1].token;
      }
      return await this.generateToken();
    } catch (error) {
      throw new Error('Failed to get current token: ' + error.message);
    }
  }

  async markTokenAsSynced(token) {
    try {
      const tokens = await this.getStoredTokens();
      const updatedTokens = tokens.map(t => 
        t.token === token ? { ...t, synced: true } : t
      );

      await Keychain.setGenericPassword(
        'offline_tokens',
        JSON.stringify(updatedTokens),
        {
          service: this.keychainService,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED
        }
      );
    } catch (error) {
      throw new Error('Failed to mark token as synced: ' + error.message);
    }
  }

  async clearSyncedTokens() {
    try {
      const tokens = await this.getStoredTokens();
      const unsyncedTokens = tokens.filter(t => !t.synced);

      await Keychain.setGenericPassword(
        'offline_tokens',
        JSON.stringify(unsyncedTokens),
        {
          service: this.keychainService,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED
        }
      );

      return tokens.length - unsyncedTokens.length;
    } catch (error) {
      throw new Error('Failed to clear synced tokens: ' + error.message);
    }
  }

  async getAllUnsyncedTokens() {
    try {
      const tokens = await this.getStoredTokens();
      return tokens.filter(t => !t.synced);
    } catch (error) {
      throw new Error('Failed to get unsynced tokens: ' + error.message);
    }
  }

  validateToken(token) {
    if (!token || typeof token !== 'string') {
      return false;
    }

    if (!token.startsWith(this.tokenPrefix)) {
      return false;
    }

    const parts = token.substring(this.tokenPrefix.length).split('_');
    if (parts.length !== 2) {
      return false;
    }

    const timestamp = parseInt(parts[0], 10);
    if (isNaN(timestamp)) {
      return false;
    }

    const tokenString = parts[1];
    if (tokenString.length !== 64 || !/^[0-9a-f]+$/.test(tokenString)) {
      return false;
    }

    return true;
  }
}

export default new OfflineTokenGenerator();